package org.example.project.screensimport androidx.compose.material3.Textimport androidx.compose.runtime.Composableimport androidx.compose.foundation.layout.*import androidx.compose.material3.*import androidx.compose.runtime.*import androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.graphics.Colorimport androidx.compose.ui.unit.dpimport org.example.project.components.*import androidx.compose.material3.ExperimentalMaterial3Apiimport org.example.project.components.legal.TermsAgreementText@OptIn(ExperimentalMaterial3Api::class)@Composablefun LoginScreen(    onNavigateToHome: () -> Unit,) {    val sheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)    val scope = rememberCoroutineScope()    var showForgotPassword by remember { mutableStateOf(false) }    var email by remember { mutableStateOf("") }    var password by remember { mutableStateOf("") }    // Scaffold é semanticamente mais correto para telas inteiras    Scaffold(        containerColor = Color(0xFF1A1A1A)    ) { paddingValues ->        Box(            modifier = Modifier                .fillMaxSize()                .padding(paddingValues)        ) {            Column(                modifier = Modifier                    .fillMaxSize()                    .padding(horizontal = 24.dp),                verticalArrangement = Arrangement.Center,                horizontalAlignment = Alignment.CenterHorizontally            ) {                TitleInterface()                Spacer(modifier = Modifier.height(32.dp))                LoginFormUser(                    email = email,                    onEmailChange = { email = it },                    password = password,                    onPasswordChange = { password = it }                )                ForgotPasswordButton(                    onClick = { showForgotPassword = true }                )                Spacer(modifier = Modifier.height(24.dp))                Button(                    onClick = { if (email.isNotBlank()) onNavigateToHome() },                    modifier = Modifier.fillMaxWidth().height(50.dp),                    shape = MaterialTheme.shapes.medium,                    colors = ButtonDefaults.buttonColors(                        containerColor = Color.White,                        contentColor = Color.Black                    )                ) {                    Text("Login")                }            }            if (showForgotPassword) {                ModalBottomSheet(                    sheetState = sheetState,                    onDismissRequest = { showForgotPassword = false },                    containerColor = MaterialTheme.colorScheme.surface,                    dragHandle = { BottomSheetDefaults.DragHandle() }                ) {                    AccountRecoveryForm()                }            }        }    }}